mapper.select:
select titb.id, titb.tag_id, titb.tag_name, titb.brand_id, titb.brand_name, titb.tag_product, titb.remark, titb.create_by, titb.create_time, titb.update_by, titb.update_time, titb.is_delete, tt.store_tags, titb.platform_type from kol_tag_brand titb left join kol_tags tt on tt.id = titb.tag_id
and titb.brand_id = #{kolTagBrand.brandId}
and titb.brand_name like concat('%', #{kolTagBrand.brandName}, '%')
and titb.tag_name like concat('%', #{kolTagBrand.tagName}, '%')
and titb.platform_type = #{kolTagBrand.platformType}
and(
titb.store_tags like concat('%', #{item}, '%')
)
order by titb.create_time desc

